import ldap3
from ldap3 import Server, Connection, ALL

def search_user(username):
    server = Server('ldap://your_server', get_info=ALL)
    conn = Connection(server, user='cn=admin,dc=example,dc=com', password='password')
    
    if not conn.bind():
        print(f"Error while binding with server: {conn.result['description']}")
        
    search_base = 'dc=example,dc=com'  # your LDAP directory base dn
    search_filter = f'(sAMAccountName={username})'  # modify this line according to your ldap server configuration
    
    if not conn.search(search_base=search_base, search_filter=search_filter):
        print(f"Error in searching users: {conn.result['description']}")
        
    return conn.entries[0]  # Returns the first match